const UNIT_1_FR: Question[] = [
  { id: "fr-q1-1", type: "MCQ", question: "Quelle est la mission principale pour laquelle l'être humain a été créé ?", options: ["S'amuser et profiter", "Adorer Allah seul (Tawhid)", "Accumuler des richesses", "Dominer la nature"], correctAnswer: "Adorer Allah seul (Tawhid)", explanation: "Allah n'a pas créé cet univers immense par jeu ou par hasard. Il nous a créés avec un but noble : Le connaître et L'adorer.\n\nL'adoration (Al-Ibadah) n'est pas seulement la prière, c'est tout acte (parole ou action) fait avec l'intention de plaire à Allah. C'est ce qui donne un sens à notre vie.", dalil: "« Je n'ai créé les djinns et les hommes que pour qu'ils M'adorent. » (Sourate Ad-Dhariyat, 51:56)" },
  { id: "fr-q1-2", type: "BUBBLE", question: "Complétez la Shahada, la clé du Paradis :", options: ["La", "ilaha", "illa", "Allah", "dieu", "prophète"], correctAnswer: ["La", "ilaha", "illa", "Allah"], explanation: "Cette phrase divise l'histoire en deux. 'La ilaha' (Nulle divinité) est une négation de tous les faux dieux (argent, ego, statues). 'Illa Allah' (Sauf Allah) est l'affirmation que seul le Créateur mérite notre soumission absolue.\nC'est la clé du Paradis, mais une clé a besoin de dents (les bonnes actions) pour ouvrir la porte.", dalil: "« Sache donc qu'en vérité, il n'y a point de divinité à part Allah... » (47:19)" },
  { id: "fr-q1-3", type: "TRUE_FALSE", question: "Allah a besoin de nos prières pour maintenir Sa puissance.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "C'est une erreur fondamentale. Allah est 'Al-Ghani' (Le Riche, Celui qui se suffit à Lui-même). Si tous les humains avaient le cœur le plus pieux, cela n'ajouterait rien à Son Royaume. Et si tous étaient pervers, cela ne diminuerait rien.\nC'est NOUS qui avons besoin de la prière pour nous apaiser, nous guider et nous sauver.", dalil: "« Ô hommes, vous êtes les indigents ayant besoin d'Allah, et c'est Allah, Lui qui se dispense de tout... » (35:15)" },
  { id: "fr-q1-4", type: "MATCHING", question: "Reliez le Nom d'Allah à sa signification profonde", options: [], pairs: [{ left: "Al-Khaliq", right: "Le Créateur" }, { left: "Al-Malik", right: "Le Roi Souverain" }, { left: "Al-Razzaq", right: "Le Pourvoyeur" }], correctAnswer: "MATCH_ALL", explanation: "Connaître Allah par Ses noms est le cœur de la foi.\n- Al-Khaliq : Il a tout inventé sans modèle précédent.\n- Al-Malik : Il possède tout, nous ne sommes que des gérants temporaires.\n- Al-Razzaq : Il nourrit la fourmi sous terre et l'oiseau dans le ciel. Ne craignez pas pour votre subsistance.", dalil: "« C'est à Allah qu'appartiennent les noms les plus beaux. » (7:180)" },
  { id: "fr-q1-5", type: "MCQ", question: "Que signifie réellement le mot 'Islam' ?", options: ["Guerre sainte", "Soumission pacifique à Allah", "Tradition arabe", "Méditation"], correctAnswer: "Soumission pacifique à Allah", explanation: "Islam vient de la racine 'S-L-M' qui donne 'Salam' (Paix) et 'Taslim' (Soumission). \nLe musulman est celui qui trouve la Paix intérieure en déposant les armes de son ego et en acceptant volontairement la Volonté de Dieu. C'est une libération, pas une contrainte.", dalil: "-" },
  { id: "fr-q1-6", type: "BUBBLE", question: "Le message de tous les prophètes était...", options: ["Adorez", "Allah", "l'", "Unique", "les", "anges"], correctAnswer: ["Adorez", "Allah", "l'", "Unique"], explanation: "De Noé à Jésus, en passant par Moïse et Abraham (paix sur eux), le message n'a jamais changé : 'La ilaha illa Allah'. L'Islam n'est pas une nouvelle religion, c'est le rappel du message originel.", dalil: "« Et Nous n'avons envoyé avant toi aucun Messager sans lui révéler : Point de divinité en dehors de Moi... » (21:25)" },
  { id: "fr-q1-7", type: "TRUE_FALSE", question: "Il est permis de demander de l'aide spirituelle (invocations) aux morts ou aux anges.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Ceci touche au cœur du Tawhid. L'invocation (Dua) est l'essence de l'adoration. La diriger vers un autre qu'Allah (même un prophète ou un ange) est du 'Shirk' (association). Seul Allah entend tout, voit tout et peut exaucer les vœux.", dalil: "« Ce sont seulement des serviteurs honorés... » (Coran)" },
  { id: "fr-q1-8", type: "MCQ", question: "Quelle est la définition de l'Ihsan (l'Excellence) ?", options: ["Prier toute la nuit", "Adorer Allah comme si tu Le voyais", "Donner tout son argent", "Apprendre le Coran par cœur"], correctAnswer: "Adorer Allah comme si tu Le voyais", explanation: "C'est le sommet de la foi. C'est avoir la conscience permanente qu'Allah nous regarde.\n« Si tu ne Le vois pas, Lui te voit. »\nCela pousse le croyant à l'excellence dans son comportement, même quand il est seul.", dalil: "Hadith de Jibril" },
  { id: "fr-q1-9", type: "MATCHING", question: "Les 3 étapes de l'existence", options: [], pairs: [{ left: "Dunya", right: "Le champ d'action" }, { left: "Barzakh", right: "Le monde de la tombe" }, { left: "Akhira", right: "La récolte éternelle" }], correctAnswer: "MATCH_ALL", explanation: "La vie d'ici-bas (Dunya) est courte et sert d'examen. Le Barzakh est la salle d'attente. L'Akhira est la vraie vie. Le croyant intelligent est celui qui utilise la Dunya pour construire son palais dans l'Akhira.", dalil: "« La vie présente n'est que jeu et amusement... » (6:32)" },
  { id: "fr-q1-10", type: "BUBBLE", question: "Le pire péché est le...", options: ["Shirk", "Vol", "Mensonge", "Meurtre"], correctAnswer: ["Shirk"], explanation: "Le Shirk (associer des partenaires à Allah) est le seul péché qu'Allah ne pardonne pas si l'on meurt sans s'en être repenti. C'est une injustice immense envers Celui qui nous a tout donné.", dalil: "« Certes Allah ne pardonne pas qu'on Lui donne quelque associé... » (4:48)" },
  { id: "fr-q1-11", type: "TRUE_FALSE", question: "Allah nous aime plus que notre propre mère nous aime.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Dans un hadith célèbre, le Prophète (sws) a montré une mère serrant son enfant et a dit que la Miséricorde d'Allah envers Ses serviteurs est bien plus grande encore. Il veut notre bien et notre guidée, c'est nous qui nous détournons.", dalil: "Hadith (Bukhari/Muslim)" },
  { id: "fr-q1-12", type: "MCQ", question: "Qui est notre ennemi déclaré ?", options: ["Les autres humains", "Shaytan (Satan)", "La pauvreté", "La maladie"], correctAnswer: "Shaytan (Satan)", explanation: "Allah nous a avertis : Shaytan est un ennemi déclaré. Il a juré d'égarer les humains par jalousie envers Adam. Sa stratégie est de nous faire oublier Allah et d'embellir le péché.", dalil: "« Le Diable est pour vous un ennemi. Prenez-le donc pour ennemi. » (35:6)" }
];
const UNIT_2_FR: Question[] = [
    { id: "fr-q2-1", type: "BUBBLE", question: "L'Islam repose sur", options: ["cinq", "piliers", "fondamentaux", "trois", "murs"], correctAnswer: ["cinq", "piliers", "fondamentaux"], explanation: "Comme une maison a besoin de piliers pour tenir, l'Islam s'écroule sans eux. Ils sont : la Shahada, la Salat, la Zakat, le Sawm et le Hajj.", dalil: "Hadith: « L'Islam est bâti sur cinq... »" },
    { id: "fr-q2-2", type: "MATCHING", question: "Associez le pilier à son sens", options: [], pairs: [{ left: "Salat", right: "Connexion spirituelle" }, { left: "Zakat", right: "Solidarité sociale" }, { left: "Sawm", right: "Maîtrise de soi" }], correctAnswer: "MATCH_ALL", explanation: "Chaque pilier a une sagesse :\n- La prière nourrit l'âme.\n- La Zakat purifie l'argent et aide les pauvres.\n- Le jeûne apprend la discipline et l'empathie.", dalil: "-" },
    { id: "fr-q2-3", type: "MCQ", question: "Pourquoi la prière (Salat) est-elle si importante ?", options: ["C'est une gymnastique", "C'est le lien direct avec Allah", "C'est pour se reposer", "C'est une tradition"], correctAnswer: "C'est le lien direct avec Allah", explanation: "Salat vient de 'Silah' (Lien). C'est le moment où le serviteur parle à son Maître. C'est la première chose sur laquelle nous serons jugés. Si elle est valide, tout le reste sera facilité.", dalil: "-" },
    { id: "fr-q2-4", type: "TRUE_FALSE", question: "La Zakat est un impôt que l'on donne au gouvernement.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "La Zakat est un droit divin des pauvres sur les biens des riches (2.5% de l'épargne annuelle). On la donne directement aux nécessiteux pour purifier nos biens de l'avarice.", dalil: "Sourate At-Tawbah 9:60" },
    { id: "fr-q2-5", type: "MCQ", question: "Quel est le but spirituel du Ramadan ?", options: ["Perdre du poids", "Atteindre la Taqwa (Piété)", "Économiser de la nourriture", "Changer de rythme"], correctAnswer: "Atteindre la Taqwa (Piété)", explanation: "En se privant de ce qui est autorisé (manger, boire) pendant la journée, on apprend à dire 'non' à ses passions. Cela entraîne l'âme à éviter ce qui est interdit le reste de l'année.", dalil: "« ...ainsi atteindrez-vous la piété. » (2:183)" },
    { id: "fr-q2-6", type: "BUBBLE", question: "Le Hajj rappelle le jour du", options: ["Jugement", "Dernier", "rassemblement", "fête"], correctAnswer: ["Jugement", "Dernier"], explanation: "Des millions de gens, habillés du même tissu blanc (Ihram), riches comme pauvres, debout sur la plaine d'Arafat... C'est une répétition générale du Jour du Jugement devant Allah.", dalil: "-" },
    { id: "fr-q2-7", type: "TRUE_FALSE", question: "Je peux faire le Hajj avant de payer mes dettes.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "L'Islam protège les droits des gens. On doit régler ses dettes ou avoir l'accord du créancier avant de partir. Le Hajj n'est obligatoire que pour celui qui en a la 'capacité' (Istita'a) financière et physique.", dalil: "-" },
    { id: "fr-q2-8", type: "MATCHING", question: "Les temps de prière", options: [], pairs: [{ left: "Fajr", right: "Aube naissante" }, { left: "Dhuhr", right: "Zénith du soleil" }, { left: "Maghrib", right: "Coucher du soleil" }], correctAnswer: "MATCH_ALL", explanation: "Les prières sont liées au mouvement du soleil pour que le musulman vive en harmonie avec l'univers. Le temps est la ressource la plus précieuse.", dalil: "« La prière est [...] une prescription à des temps déterminés. » (4:103)" },
    { id: "fr-q2-9", type: "MCQ", question: "Que se passe-t-il si je ne peux pas utiliser d'eau pour les ablutions ?", options: ["Je ne prie pas", "Je fais le Tayammum", "Je prie sans rien", "J'attends l'eau"], correctAnswer: "Je fais le Tayammum", explanation: "L'Islam est facilité. Si l'eau manque ou est nuisible (maladie), on utilise la terre propre (Tayammum) pour s'essuyer symboliquement le visage et les mains.", dalil: "Sourate An-Nisa 4:43" },
    { id: "fr-q2-10", type: "BUBBLE", question: "La Shahada comporte", options: ["une", "négation", "et", "une", "affirmation"], correctAnswer: ["une", "négation", "et", "une", "affirmation"], explanation: "1. 'La ilaha' (Négation) : Je rejette tout faux pouvoir.\n2. 'Illa Allah' (Affirmation) : J'accepte l'autorité unique d'Allah.", dalil: "-" },
    { id: "fr-q2-11", type: "TRUE_FALSE", question: "Si je suis très malade, la prière n'est plus obligatoire.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Tant que l'esprit est là, la prière reste obligatoire. Si on ne peut pas se lever, on prie assis. Sinon couché. Sinon avec les yeux. C'est le seul pilier qui ne tombe jamais.", dalil: "Hadith d'Imran bin Husain" },
    { id: "fr-q2-12", type: "MCQ", question: "Quel est le 'Takbir' ?", options: ["Dire SubhanAllah", "Dire Allahu Akbar", "Dire Alhamdulillah", "Lire le Coran"], correctAnswer: "Dire Allahu Akbar", explanation: "Cela signifie 'Allah est Le Plus Grand'. Plus grand que mes soucis, que mon travail, que mes désirs. C'est par cela qu'on entre en prière.", dalil: "-" }
];
const UNIT_3_FR: Question[] = [
    { id: "fr-q3-1", type: "BUBBLE", question: "L'Iman (Foi) comporte", options: ["six", "piliers", "invisibles", "cinq", "visibles"], correctAnswer: ["six", "piliers", "invisibles"], explanation: "Croire en : Allah, Ses Anges, Ses Livres, Ses Messagers, le Jour Dernier, le Destin (Qadar). Si un seul manque, la foi n'est pas valide.", dalil: "Hadith Jibril" },
    { id: "fr-q3-2", type: "MCQ", question: "De quoi sont créés les Anges ?", options: ["De feu", "De lumière", "D'argile", "De vent"], correctAnswer: "De lumière", explanation: "Ils sont des créatures de pure lumière, sans libre arbitre pour désobéir. Ils exécutent parfaitement les ordres d'Allah.", dalil: "Hadith" },
    { id: "fr-q3-3", type: "TRUE_FALSE", question: "Croire au Destin signifie qu'on ne doit rien faire et attendre.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "C'est une mauvaise compréhension. Le Destin est le savoir d'Allah, mais nous devons agir. Le Prophète a dit : 'Attache ta chamelle ET place ta confiance en Allah'. L'effort est obligatoire.", dalil: "-" },
    { id: "fr-q3-4", type: "MATCHING", question: "Les Livres Révélés", options: [], pairs: [{ left: "Tawrat (Torah)", right: "Moussa" }, { left: "Injil (Évangile)", right: "Issa" }, { left: "Zabur (Psaumes)", right: "Dawud" }], correctAnswer: "MATCH_ALL", explanation: "Nous croyons en l'origine divine de ces livres, bien qu'ils aient été altérés par les hommes par la suite. Le Coran est le dernier rappel, protégé par Allah.", dalil: "-" },
    { id: "fr-q3-5", type: "MCQ", question: "Quelle est la différence entre un Prophète (Nabi) et un Messager (Rasul) ?", options: ["Aucune", "Le Messager apporte une nouvelle loi", "Le Prophète est un ange", "Le Messager ne reçoit pas de livre"], correctAnswer: "Le Messager apporte une nouvelle loi", explanation: "Tout Messager est Prophète, mais tout Prophète n'est pas Messager. Le Messager (comme Moïse, Jésus, Muhammad) vient avec une législation majeure pour un peuple.", dalil: "-" },
    { id: "fr-q3-6", type: "BUBBLE", question: "Le Jour Dernier est le jour de la", options: ["Justice", "absolue", "vengeance", "fin"], correctAnswer: ["Justice", "absolue"], explanation: "Ce jour-là, aucune injustice ne sera tolérée. Même l'animal sans cornes obtiendra justice de celui qui l'a frappé.", dalil: "-" },
    { id: "fr-q3-7", type: "TRUE_FALSE", question: "La foi augmente et diminue.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "La foi n'est pas statique. Elle augmente par l'obéissance, les bonnes actions et le savoir. Elle diminue par les péchés et'ignorance.", dalil: "Consensus des savants" },
    { id: "fr-q3-8", type: "MATCHING", question: "Les Anges Spéciaux", options: [], pairs: [{ left: "Jibril", right: "Porteur de la Révélation" }, { left: "Malik", right: "Gardien de l'Enfer" }, { left: "Malak al-Mawt", right: "Ange de la Mort" }], correctAnswer: "MATCH_ALL", explanation: "Chaque ange a une fonction précise dans l'administration de l'univers sous l'ordre d'Allah.", dalil: "-" },
    { id: "fr-q3-9", type: "MCQ", question: "Qu'est-ce que le 'Ghayb' ?", options: ["L'Invisible", "Le Futur", "Le Passé", "Le Mensonge"], correctAnswer: "L'Invisible", explanation: "Le croyant croit au 'Ghayb' (Ce qu'il ne voit pas : Allah, Anges, Paradis...) sur la base de la confiance en la révélation. C'est le premier test de la foi.", dalil: "« Ceux qui croient à l'invisible... » (2:3)" },
    { id: "fr-q3-10", type: "BUBBLE", question: "La tombe est soit un jardin du", options: ["Paradis", "soit", "un", "trou", "de", "l'", "Enfer"], correctAnswer: ["Paradis", "soit", "un", "trou", "de", "l'", "Enfer"], explanation: "La vie dans la tombe (Barzakh) est réelle. Elle est la première étape de la rétribution.", dalil: "Hadith" },
    { id: "fr-q3-11", type: "TRUE_FALSE", question: "Les Djinns sont tous mauvais.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Comme les humains, les Djinns ont le libre arbitre. Il y a parmi eux des musulmans, des chrétiens, des athées, des bons et des mauvais.", dalil: "Sourate Al-Jinn" },
    { id: "fr-q3-12", type: "MCQ", question: "Que signifie 'La Hawla wa la Quwwata illa Billah' ?", options: ["Dieu est grand", "Il n'y a de force et de puissance que par Allah", "Merci mon Dieu", "Pardonnez-moi"], correctAnswer: "Il n'y a de force et de puissance que par Allah", explanation: "C'est un trésor du Paradis. Cela signifie que je ne peux rien changer, ni bouger, ni réussir sans l'aide d'Allah. C'est l'abandon total de sa propre prétention à la force.", dalil: "-" }
];
const UNIT_4_FR: Question[] = [
    { id: "fr-q4-1", type: "MCQ", question: "Quelle est la définition dogmatique du Coran ?", options: ["La parole de Jibril", "La parole incréée d'Allah", "Les mots du Prophète (sws)", "Un livre historique"], correctAnswer: "La parole incréée d'Allah", explanation: "Le Coran n'est pas une création, c'est un Attribut d'Allah (Sa Parole - Kalam). Il a été révélé à Muhammad (sws) par l'intermédiaire de Jibril, en langue arabe claire.", dalil: "« Et si l'un des associateurs te demande asile... afin qu'il entende la parole d'Allah » (9:6)" },
    { id: "fr-q4-2", type: "BUBBLE", question: "Le Coran a été révélé sur", options: ["vingt", "trois", "ans", "une", "nuit"], correctAnswer: ["vingt", "trois", "ans"], explanation: "La révélation fut graduelle (13 ans à La Mecque, 10 ans à Médine) pour raffermir le cœur du Prophète et faciliter la mise en pratique par les Compagnons.", dalil: "« Nous l'avons fait descendre par fragments... » (17:106)" },
    { id: "fr-q4-3", type: "MATCHING", question: "Les Noms du Coran", options: [], pairs: [{ left: "Al-Furqan", right: "Le Discernement (Vrai/Faux)" }, { left: "Al-Huda", right: "La Guidée" }, { left: "Al-Shifa", right: "La Guérison" }], correctAnswer: "MATCH_ALL", explanation: "Le Coran a plusieurs noms : Furqan car il sépare le Vrai du Faux, Huda car il guide vers le droit chemin, et Shifa car il guérit les cœurs du doute et les corps de la maladie.", dalil: "« Ce Coran guide vers ce qu'il y a de plus droit... » (17:9)" },
    { id: "fr-q4-4", type: "TRUE_FALSE", question: "Le Coran que nous lisons aujourd'hui est différent de celui du Prophète.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "C'est le miracle éternel. Allah a promis de le préserver. Pas une lettre n'a changé depuis 1400 ans, contrairement aux livres précédents. Des millions de personnes le connaissent par cœur.", dalil: "« En vérité c'est Nous qui avons fait descendre le Coran, et c'est Nous qui en sommes gardien. » (15:9)" },
    { id: "fr-q4-5", type: "MCQ", question: "Quelle sourate est appelée 'La Mère du Livre' (Umm al-Kitab) ?", options: ["Al-Baqara", "Al-Fatiha", "Yasin", "Al-Ikhlas"], correctAnswer: "Al-Fatiha", explanation: "Elle résume tout le Coran : Tawhid, Louange, Promesse, Menace, et Guidée. La prière n'est pas valide sans sa récitation.", dalil: "Hadith: « Pas de prière pour celui qui ne récite pas l'Ouverture du Livre. »" },
    { id: "fr-q4-6", type: "BUBBLE", question: "Le verset du Trône (Ayat al-Kursi) est", options: ["le", "plus", "grand", "verset", "sourate"], correctAnswer: ["le", "plus", "grand", "verset"], explanation: "Ce verset (2:255) décrit la Grandeur, la Vie et la Souveraineté d'Allah. Le lire protège du mal et des démons, surtout avant de dormir.", dalil: "Hadith Sahih" },
    { id: "fr-q4-7", type: "TRUE_FALSE", question: "Il est obligatoire d'être en état de pureté (Wudu) pour toucher le Mous-haf (Livre arabe).", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Selon la majorité des 4 écoles juridiques, par respect pour la Parole d'Allah, on ne touche le texte arabe qu'avec les ablutions. Cependant, on peut le réciter de mémoire ou lire une traduction sans wudu.", dalil: "« Ne le touchent que les purifiés. » (56:79)" },
    { id: "fr-q4-8", type: "MATCHING", question: "Sourates & Mérites", options: [], pairs: [{ left: "Al-Ikhlas", right: "Équivaut à 1/3 du Coran" }, { left: "Al-Mulk", right: "Protège du châtiment de la tombe" }, { left: "Al-Kahf", right: "Lumière du Vendredi" }], correctAnswer: "MATCH_ALL", explanation: "Certaines sourates ont des 'fada'il' (mérites) spécifiques mentionnés par le Prophète (sws) pour nous encourager à les lire régulièrement.", dalil: "-" },
    { id: "fr-q4-9", type: "MCQ", question: "Qu'est-ce que le 'Tajweed' ?", options: ["Chanter fort", "L'art d'embellir et bien prononcer le Coran", "Lire très vite", "Traduire le Coran"], correctAnswer: "L'art d'embellir et bien prononcer le Coran", explanation: "Tajweed signifie 'améliorer'. C'est donner à chaque lettre son droit en respectant les points de sortie et les règles, comme l'a enseigné le Prophète (sws).", dalil: "« Et récite le Coran, lentement et clairement. » (73:4)" },
    { id: "fr-q4-10", type: "BUBBLE", question: "Celui qui lit une lettre du Coran a", options: ["dix", "bonnes", "actions", "une"], correctAnswer: ["dix", "bonnes", "actions"], explanation: "La miséricorde d'Allah est immense. Alif est une lettre, Lam est une lettre, Mim est une lettre. Donc 'Alif-Lam-Mim' rapporte 30 Hassanates !", dalil: "Hadith (Tirmidhi)" },
    { id: "fr-q4-11", type: "TRUE_FALSE", question: "Le Coran s'adresse uniquement aux Arabes.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Le Coran est un message universel pour toute l'humanité et même pour les Djinns, jusqu'à la fin des temps. Il commence par 'Louange à Allah, Seigneur des mondes'.", dalil: "« Ce n'est qu'un rappel pour l'univers. » (81:27)" },
    { id: "fr-q4-12", type: "MCQ", question: "Que signifie 'Tadabbur' ?", options: ["Mémoriser par cœur", "Méditer sur le sens des versets", "Lire sans comprendre", "Poser le Coran sur une étagère"], correctAnswer: "Méditer sur le sens des versets", explanation: "Le but ultime de la lecture n'est pas la vitesse, mais la compréhension et la mise en pratique. Le Coran a été révélé pour être médité, afin qu'il transforme nos cœurs.", dalil: "« Ne méditent-ils pas sur le Coran ? » (4:82)" }
];
const UNIT_5_FR: Question[] = [
    { id: "fr-q5-1", type: "MCQ", question: "Quelle est la condition clé pour que la prière soit acceptée (après la foi) ?", options: ["Avoir de beaux vêtements", "La Pureté (Tahara)", "Prier dans une mosquée", "Prier vite"], correctAnswer: "La Pureté (Tahara)", explanation: "Sans pureté (Wudu ou Ghusl), la prière est invalide. C'est la clé de la prière, tout comme la prière est la clé du Paradis.", dalil: "Hadith: « Allah n'accepte pas la prière sans purification. »" },
    { id: "fr-q5-2", type: "BUBBLE", question: "La position où le serviteur est le plus proche d'Allah est", options: ["la", "prosternation", "Sujud", "debout"], correctAnswer: ["la", "prosternation", "Sujud"], explanation: "En mettant la partie la plus noble de notre corps (le visage) au sol par humilité, nous nous élevons spirituellement. C'est le moment idéal pour faire des invocations (Dua).", dalil: "Hadith Sahih" },
    { id: "fr-q5-3", type: "MATCHING", question: "Piliers de la Salat", options: [], pairs: [{ left: "Takbir Ihram", right: "L'entrée en prière" }, { left: "Fatiha", right: "La lecture obligatoire" }, { left: "Taslim", right: "La sortie de prière" }], correctAnswer: "MATCH_ALL", explanation: "La prière est composée de piliers (Arkan) qui, s'ils sont oubliés, invalident la Rak'a. Le Takbir initial interdit les paroles mondaines, et le Taslim les autorise à nouveau.", dalil: "-" },
    { id: "fr-q5-4", type: "TRUE_FALSE", question: "Regarder le ciel pendant la prière est recommandé.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "C'est interdit et sévèrement blâmé. Le regard doit être baissé vers l'endroit de la prosternation pour favoriser la concentration (Khushu) et l'humilité devant le Roi des rois.", dalil: "Hadith (Bukhari)" },
    { id: "fr-q5-5", type: "MCQ", question: "Qu'est-ce que le 'Khushu' ?", options: ["La vitesse", "L'humilité et la concentration du cœur", "La récitation à voix haute", "Les mouvements parfaits"], correctAnswer: "L'humilité et la concentration du cœur", explanation: "C'est l'âme de la prière. Une prière sans Khushu est comme un corps sans âme. C'est être conscient qu'on se tient devant Allah.", dalil: "« Bienheureux sont les croyants, ceux qui sont humbles dans leur Salât » (23:1-2)" },
    { id: "fr-q5-6", type: "BUBBLE", question: "La prière en groupe vaut", options: ["vingt", "sept", "degrés", "mieux", "deux"], correctAnswer: ["vingt", "sept", "degrés", "mieux"], explanation: "L'Islam encourage l'unité. Prier à la mosquée ou en groupe renforce les liens fraternels et rapporte 27 fois plus de récompenses que la prière seul.", dalil: "Hadith (Bukhari/Muslim)" },
    { id: "fr-q5-7", type: "TRUE_FALSE", question: "Si j'oublie une prière et que je m'en souviens le lendemain, c'est trop tard.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Il n'y a pas d'expiation pour la prière oubliée ou dormie si ce n'est de la faire dès qu'on s'en souvient. Allah n'oublie pas, mais Il pardonne l'oubli involontaire de l'humain.", dalil: "Hadith: « Celui qui dort ou oublie une prière, qu'il la prie lorsqu'il s'en souvient. »" },
    { id: "fr-q5-8", type: "MATCHING", question: "Les types de prières", options: [], pairs: [{ left: "Fard", right: "Obligatoire (5x)" }, { left: "Sunnah", right: "Recommandée" }, { left: "Witr", right: "Clôture de la nuit" }], correctAnswer: "MATCH_ALL", explanation: "Les prières obligatoires sont la dette qu'on doit à Allah. Les prières surérogatoires (Sunnah) comblent les manques des obligatoires et nous rapprochent de Lui.", dalil: "Hadith Qudsi" },
    { id: "fr-q5-9", type: "MCQ", question: "Que dire pendant l'inclinaison (Ruku) ?", options: ["Subhana Rabbiyal A'la", "Subhana Rabbiyal 'Adhim", "Sami Allahu liman hamidah", "Allahu Akbar"], correctAnswer: "Subhana Rabbiyal 'Adhim", explanation: "On dit 'Gloire à mon Seigneur l'Immense'. C'est une position de soumission et de glorification de la Grandeur d'Allah.", dalil: "-" },
    { id: "fr-q5-10", type: "BUBBLE", question: "La prière du vendredi remplace le", options: ["Dhuhr", "Asr", "Maghrib", "Fajr"], correctAnswer: ["Dhuhr"], explanation: "Le Vendredi (Jumu'a) est la fête hebdomadaire des musulmans. On écoute le sermon (Khutba) puis on prie 2 unités au lieu des 4 du Dhuhr.", dalil: "Sourate Al-Jumu'a" },
    { id: "fr-q5-11", type: "TRUE_FALSE", question: "Manger ou boire volontairement annule la prière.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "La prière exige une déconnexion totale des besoins mondains. Introduire quelque chose dans l'estomac volontairement rompt cette connexion et annule l'acte.", dalil: "Consensus des savants" },
    { id: "fr-q5-12", type: "MCQ", question: "Quel est le premier acte sur lequel le serviteur sera interrogé le Jour du Jugement ?", options: ["Sa Zakat", "Sa Salat", "Son Jeûne", "Son comportement"], correctAnswer: "Sa Salat", explanation: "Le Prophète (sws) a dit : « Si elle est valide, il a réussi et prospéré. Si elle est corrompue, il a échoué et perdu. » C'est le baromètre de notre foi.", dalil: "Hadith (Tirmidhi)" }
];
const UNIT_6_FR: Question[] = [
    { id: "fr-q6-1", type: "MCQ", question: "De quel prophète descend Muhammad (sws) ?", options: ["Ishaq (Isaac)", "Ismail (Ismaël)", "Yusuf (Joseph)", "Moussa (Moïse)"], correctAnswer: "Ismail (Ismaël)", explanation: "Il est le descendant d'Ibrahim (Abraham) par son fils aîné Ismail. C'est l'exaucement de l'invocation d'Ibrahim faite à la Mecque des siècles plus tôt.", dalil: "« Notre Seigneur! Envoie l'un des leurs comme messager... » (2:129)" },
    { id: "fr-q6-2", type: "BUBBLE", question: "Le Prophète est né orphelin de", options: ["père", "mère", "grand-père", "oncle"], correctAnswer: ["père"], explanation: "Son père Abdullah est mort alors qu'il était encore dans le ventre de sa mère Amina. Allah l'a éduqué Lui-même à travers cette épreuve de l'orphelinat.", dalil: "« Ne t'a-t-Il pas trouvé orphelin ? Alors Il t'a accueilli... » (93:6)" },
    { id: "fr-q6-3", type: "MATCHING", question: "Personnages clés", options: [], pairs: [{ left: "Abu Bakr", right: "Le meilleur ami" }, { left: "Ali", right: "Le cousin courageux" }, { left: "Abu Talib", right: "L'oncle protecteur" }], correctAnswer: "MATCH_ALL", explanation: "Sa vie est entourée de figures marquantes : Abu Bakr le Véridique, Ali le premier enfant converti, et son oncle qui l'a protégé sans jamais se convertir.", dalil: "-" },
    { id: "fr-q6-4", type: "TRUE_FALSE", question: "Le Prophète (sws) a été envoyé uniquement pour les Arabes.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Contrairement aux prophètes précédents envoyés à leur peuple spécifique, Muhammad (sws) est le Sceau des prophètes, envoyé comme Miséricorde pour l'Univers entier (Humains et Djinns).", dalil: "« Et Nous ne t'avons envoyé qu'en miséricorde pour l'univers. » (21:107)" },
    { id: "fr-q6-5", type: "MCQ", question: "Quel surnom les Mecquois lui donnaient-ils AVANT la révélation ?", options: ["Le Poète", "Le Magicien", "Al-Amin (Le Digne de Confiance)", "Le Chef"], correctAnswer: "Al-Amin (Le Digne de Confiance)", explanation: "Même avant l'Islam, il était connu pour sa moralité irréprochable et son honnêteté absolue. C'est un argument fort contre ceux qui l'ont traité de menteur par la suite.", dalil: "-" },
    { id: "fr-q6-6", type: "BUBBLE", question: "La première femme à avoir cru en lui est", options: ["Khadija", "Aisha", "Fatima", "Maryam"], correctAnswer: ["Khadija"], explanation: "Son épouse Khadija (ra) a été son premier soutien psychologique et financier. Elle l'a cru quand tout le monde le rejetait. 'Allah ne m'a pas donné de meilleure épouse qu'elle', disait-il.", dalil: "-" },
    { id: "fr-q6-7", type: "MATCHING", question: "Événements majeurs", options: [], pairs: [{ left: "Hira", right: "Début de la Révélation" }, { left: "Hijra", right: "Émigration vers Médine" }, { left: "Badr", right: "Première grande victoire" }], correctAnswer: "MATCH_ALL", explanation: "La grotte de Hira marque le début de la lumière. La Hijra marque le début de l'État islamique. Badr marque le début de la victoire de la vérité sur le faux.", dalil: "-" },
    { id: "fr-q6-8", type: "TRUE_FALSE", question: "Lors de la conquête de La Mecque, le Prophète a vengé les musulmans torturés.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "C'est l'un des plus grands moments de pardon de l'histoire. Avec 10 000 hommes, il pouvait tout détruire, mais il a dit aux Mecquois : 'Partez, vous êtes libres'.", dalil: "Seerah Ibn Hisham" },
    { id: "fr-q6-9", type: "MCQ", question: "Qu'est-ce que la Sunnah ?", options: ["Le Coran", "Les paroles, actes et approbations du Prophète", "L'histoire des arabes", "Les avis des savants"], correctAnswer: "Les paroles, actes et approbations du Prophète", explanation: "La Sunnah est la deuxième source de l'Islam. Elle explique le Coran. On ne peut pas pratiquer l'Islam (comme prier) sans suivre la Sunnah.", dalil: "« Prenez ce que le Messager vous donne; et ce qu'il vous interdit, abstenez-vous en. » (59:7)" },
    { id: "fr-q6-10", type: "BUBBLE", question: "Le miracle physique du Prophète est le voyage", options: ["Nocturne", "Isra", "et", "l'", "Ascension", "Miraj"], correctAnswer: ["Nocturne", "Isra", "et", "l'", "Ascension", "Miraj"], explanation: "En une nuit, il a voyagé de La Mecque à Jérusalem (Isra), puis est monté traverser les 7 cieux (Miraj) pour rencontrer Allah et recevoir l'ordre de la prière.", dalil: "Sourate Al-Isra (17:1)" },
    { id: "fr-q6-11", type: "TRUE_FALSE", question: "On peut être un croyant complet sans aimer le Prophète.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "L'amour du Prophète (sws) n'est pas une option. Il doit être plus cher à notre cœur que nos parents, nos enfants et nous-mêmes. C'est cet amour qui nous pousse à le suivre.", dalil: "Hadith: « Aucun de vous ne sera croyant tant que je ne lui serai pas plus cher... »" },
    { id: "fr-q6-12", type: "MCQ", question: "Où le Prophète (sws) est-il enterré ?", options: ["À La Mecque", "À Jérusalem", "À Médine", "Au Ciel"], correctAnswer: "À Médine", explanation: "Il est mort dans la chambre de son épouse Aisha, et a été enterré à l'endroit même de sa mort. Sa tombe se trouve aujourd'hui dans la Mosquée du Prophète (Masjid An-Nabawi).", dalil: "-" }
];

// --- UNITS 7-12 (FR) ---
const UNIT_7_FR: Question[] = [
  { id: "fr-q7-1", type: "MCQ", question: "Lequel de ces éléments n'est PAS une condition du Wudu ?", options: ["L'intention (Niyyah)", "Utiliser du savon", "L'eau pure", "L'ordre des actions"], correctAnswer: "Utiliser du savon", explanation: "L'eau seule suffit pour se purifier rituellement (Tahara). Le savon est pour la propreté physique, pas rituelle. L'eau doit être 'Tahur' (pure et purifiante).", dalil: "Hadith" },
  { id: "fr-q7-2", type: "TRUE_FALSE", question: "Dormir profondément annule les ablutions (Wudu).", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Le sommeil profond (où l'on perd conscience de son corps) rompt les ablutions car on ne maîtrise plus ses gaz. Le sommeil léger assis ne l'annule pas forcément.", dalil: "Hadith Safwan bin Assal" },
  { id: "fr-q7-3", type: "MATCHING", question: "Types d'impuretés", options: [], pairs: [{ left: "Hadath Mineur", right: "Nécessite Wudu" }, { left: "Hadath Majeur", right: "Nécessite Ghusl" }, { left: "Najasah", right: "Souillure physique" }], correctAnswer: "MATCH_ALL", explanation: "Le Hadath est un état (sommeil, relations conjugales) qui demande purification. La Najasah est une matière impure (urine, sang) qu'il faut laver.", dalil: "-" },
  { id: "fr-q7-4", type: "BUBBLE", question: "L'eau de mer est", options: ["pure", "et", "purifiante", "sale", "interdite"], correctAnswer: ["pure", "et", "purifiante"], explanation: "Le Prophète (sws) a dit à propos de la mer : 'Son eau est purifiante et ses animaux morts sont licites à la consommation.'", dalil: "Hadith (Abu Dawud)" },
  { id: "fr-q7-5", type: "MCQ", question: "Quand le Ghusl (grandes ablutions) est-il obligatoire ?", options: ["Avant la prière du vendredi", "Après les relations conjugales", "Avant de dormir", "Après avoir mangé"], correctAnswer: "Après les relations conjugales", explanation: "Le Ghusl est obligatoire après l'état de Janaba (impureté majeure) ou la fin des menstrues. Pour le vendredi, c'est une Sunnah très recommandée.", dalil: "Sourate Al-Ma'idah 5:6" },
  { id: "fr-q7-6", type: "TRUE_FALSE", question: "Le vernis à ongles imperméable empêche la validité du Wudu.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "L'eau doit toucher directement l'ongle. Tout ce qui crée une couche imperméable (vernis, colle) doit être retiré avant le Wudu.", dalil: "Consensus" },
  { id: "fr-q7-7", type: "MATCHING", question: "Actes du Wudu", options: [], pairs: [{ left: "Laver le visage", right: "Obligation (Fard)" }, { left: "Laver 3 fois", right: "Recommandation (Sunnah)" }, { left: "Passer l'eau dans la bouche", right: "Sunnah / Obligation selon l'école" }], correctAnswer: "MATCH_ALL", explanation: "Il y a des piliers sans lesquels le Wudu est nul, et des Sunnahs qui ajoutent de la récompense.", dalil: "-" },
  { id: "fr-q7-8", type: "BUBBLE", question: "Avant de commencer le Wudu, on dit", options: ["Bismillah", "Alhamdulillah", "Allahu", "Akbar"], correctAnswer: ["Bismillah"], explanation: "Il est recommandé de commencer toute action importante, y compris les ablutions, par le nom d'Allah.", dalil: "Hadith" },
  { id: "fr-q7-9", type: "MCQ", question: "Que faire si on saigne d'une petite coupure après le Wudu ?", options: ["Refaire le Wudu", "Laver le sang et prier", "Arrêter de prier", "Faire le Tayammum"], correctAnswer: "Laver le sang et prier", explanation: "Selon la majorité des savants, le sang (sauf menstrues) n'annule pas les ablutions, mais il faut nettoyer la souillure physique (Najasah) si elle est abondante.", dalil: "-" },
  { id: "fr-q7-10", type: "TRUE_FALSE", question: "Le Tayammum se fait avec de l'eau pure.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Le Tayammum est l'ablution sèche. Il se fait avec de la terre propre ou de la pierre lorsqu'il n'y a pas d'eau ou qu'on ne peut pas l'utiliser.", dalil: "Sourate An-Nisa 4:43" }
];
const UNIT_8_FR: Question[] = [
  { id: "fr-q8-1", type: "BUBBLE", question: "L'Adhan commence par", options: ["Allahu", "Akbar", "quatre", "fois"], correctAnswer: ["Allahu", "Akbar", "quatre", "fois"], explanation: "L'appel commence par proclamer la Grandeur d'Allah pour rappeler que rien n'est plus important que la prière à cet instant.", dalil: "-" },
  { id: "fr-q8-2", type: "MCQ", question: "Qui fut le premier muezzin de l'Islam ?", options: ["Abu Bakr", "Bilal Ibn Rabah", "Omar Ibn Khattab", "Ali"], correctAnswer: "Bilal Ibn Rabah", explanation: "Ancien esclave abyssinien à la voix magnifique, il a été choisi par le Prophète (sws) pour appeler les gens à la prière à Médine.", dalil: "Seerah" },
  { id: "fr-q8-3", type: "TRUE_FALSE", question: "Il est recommandé de parler pendant l'Adhan.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Il faut écouter et répéter ce que dit le muezzin pour gagner son intercession. C'est un moment d'exaucement des invocations.", dalil: "Hadith" },
  { id: "fr-q8-4", type: "MATCHING", question: "Paroles de l'Adhan", options: [], pairs: [{ left: "Hayya 'ala-s-salah", right: "Venez à la prière" }, { left: "Hayya 'ala-l-falah", right: "Venez au succès" }, { left: "Allahu Akbar", right: "Allah est le plus grand" }], correctAnswer: "MATCH_ALL", explanation: "L'Adhan est un appel au succès véritable, qui se trouve dans la prière et la soumission à Allah.", dalil: "-" },
  { id: "fr-q8-5", type: "MCQ", question: "Que répond-on quand le muezzin dit 'Hayya 'ala-s-salah' ?", options: ["Allahu Akbar", "La hawla wa la quwwata illa billah", "Amin", "SubhanAllah"], correctAnswer: "La hawla wa la quwwata illa billah", explanation: "On reconnaît qu'on n'a ni la force ni le pouvoir de se lever pour prier sans l'aide d'Allah.", dalil: "Hadith (Muslim)" },
  { id: "fr-q8-6", type: "BUBBLE", question: "L'Iqama est l'appel", options: ["juste", "avant", "la", "prière", "demain"], correctAnswer: ["juste", "avant", "la", "prière"], explanation: "L'Iqama annonce que la prière en groupe va commencer immédiatement. Ses paroles sont similaires à l'Adhan mais souvent prononcées une seule fois.", dalil: "-" },
  { id: "fr-q8-7", type: "TRUE_FALSE", question: "L'Adhan du Fajr contient une phrase supplémentaire.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Le muezzin ajoute : 'As-salatu khayrun mina-n-nawm' (La prière est meilleure que le sommeil) deux fois.", dalil: "Hadith" },
  { id: "fr-q8-8", type: "MATCHING", question: "Après l'Adhan", options: [], pairs: [{ left: "Salawat", right: "Prier sur le Prophète" }, { left: "Dua Al-Wasilah", right: "Demander la station louable" }, { left: "Dua personnel", right: "Moment exaucé" }], correctAnswer: "MATCH_ALL", explanation: "Celui qui demande à Allah d'accorder la 'Wasilah' (le plus haut degré du Paradis) au Prophète (sws) obtiendra son intercession.", dalil: "Hadith (Bukhari)" },
  { id: "fr-q8-9", type: "MCQ", question: "Comment les muezzins seront-ils reconnus le Jour du Jugement ?", options: ["Ils auront des couronnes", "Ils auront les cous les plus longs", "Ils seront vêtus de vert", "Ils voleront"], correctAnswer: "Ils auront les cous les plus longs", explanation: "C'est une métaphore pour dire qu'ils seront fiers, honorés et visibles par tous pour avoir appelé les gens à Allah.", dalil: "Hadith (Muslim)" },
  { id: "fr-q8-10", type: "BUBBLE", question: "Entre l'Adhan et l'Iqama, l'invocation n'est", options: ["pas", "rejetée", "jamais", "acceptée"], correctAnswer: ["pas", "rejetée"], explanation: "C'est l'un des moments privilégiés où Allah exauce les invocations de Ses serviteurs.", dalil: "Hadith (Abu Dawud)" }
];
const UNIT_9_FR: Question[] = [
  { id: "fr-q9-1", type: "MCQ", question: "Quel est le pourcentage de Zakat sur l'épargne ?", options: ["10%", "2.5%", "50%", "1%"], correctAnswer: "2.5%", explanation: "Si votre épargne dépasse le seuil (Nisab) et reste un an lunaire, vous devez donner 2.5% (1/40ème) aux pauvres.", dalil: "-" },
  { id: "fr-q9-2", type: "MATCHING", question: "Bénéficiaires de la Zakat", options: [], pairs: [{ left: "Faqir", right: "Le Pauvre" }, { left: "Miskin", right: "Le Nécessiteux" }, { left: "Ibn Sabil", right: "Le Voyageur" }], correctAnswer: "MATCH_ALL", explanation: "La Zakat a 8 catégories de bénéficiaires précises mentionnées dans le Coran (Sourate 9:60).", dalil: "Sourate At-Tawbah 9:60" },
  { id: "fr-q9-3", type: "TRUE_FALSE", question: "La Zakat purifie l'argent et ne le diminue pas.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Le Prophète (sws) a juré : 'Jamais une aumône n'a diminué une richesse'. Allah remplace ce qui est donné par la Baraka.", dalil: "Hadith" },
  { id: "fr-q9-4", type: "BUBBLE", question: "Le seuil minimum pour payer la Zakat s'appelle le", options: ["Nisab", "Hawl", "Sadaqa", "Fitr"], correctAnswer: ["Nisab"], explanation: "Le Nisab est l'équivalent de 85 grammes d'or. Si on possède moins que cela, la Zakat n'est pas obligatoire.", dalil: "-" },
  { id: "fr-q9-5", type: "MCQ", question: "Qu'est-ce que Zakat al-Fitr ?", options: ["La zakat sur l'or", "La zakat donnée à la fin du Ramadan", "La zakat sur les récoltes", "Une aumône volontaire"], correctAnswer: "La zakat donnée à la fin du Ramadan", explanation: "C'est une petite quantité de nourriture (ou son équivalent) donnée avant la prière de l'Aïd pour purifier le jeûneur et nourrir les pauvres ce jour-là.", dalil: "Hadith (Bukhari)" },
  { id: "fr-q9-6", type: "TRUE_FALSE", question: "Je peux donner ma Zakat obligatoire à mes parents s'ils sont pauvres.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "On ne peut pas donner la Zakat à ceux dont on a la charge légale (parents, enfants, épouse). On doit subvenir à leurs besoins avec notre propre argent.", dalil: "Consensus" },
  { id: "fr-q9-7", type: "MATCHING", question: "Types de biens soumis à la Zakat", options: [], pairs: [{ left: "Or et Argent", right: "2.5%" }, { left: "Récoltes agricoles", right: "5% ou 10%" }, { left: "Bétail", right: "Selon le nombre" }], correctAnswer: "MATCH_ALL", explanation: "La Zakat ne touche pas seulement l'argent, mais aussi l'or, les marchandises de commerce, les récoltes et le bétail.", dalil: "-" },
  { id: "fr-q9-8", type: "BUBBLE", question: "La Zakat purifie l'âme de", options: ["l'", "avarice", "et", "de", "l'égoïsme"], correctAnswer: ["l'", "avarice", "et", "de", "l'égoïsme"], explanation: "Le mot Zakat vient de 'Tazkiyah' qui signifie purification et accroissement.", dalil: "« Prélève de leurs biens une aumône par laquelle tu les purifies... » (9:103)" },
  { id: "fr-q9-9", type: "MCQ", question: "La Zakat est-elle une faveur du riche envers le pauvre ?", options: ["Oui, c'est un cadeau", "Non, c'est le droit du pauvre", "C'est un prêt", "C'est une taxe de l'état"], correctAnswer: "Non, c'est le droit du pauvre", explanation: "L'argent appartient à Allah. Il a assigné une part de cet argent comme étant le droit strict des pauvres. Le riche ne fait que rendre ce qui ne lui appartient pas.", dalil: "« Et dans leurs biens, il y a un droit reconnu pour le mendiant et le déshérité. » (70:24-25)" },
  { id: "fr-q9-10", type: "TRUE_FALSE", question: "Donner la Sadaqa (aumône volontaire) efface les péchés.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Le Prophète (sws) a dit : 'L'aumône éteint le péché comme l'eau éteint le feu.'", dalil: "Hadith (Tirmidhi)" }
];
const UNIT_10_FR: Question[] = [
  { id: "fr-q10-1", type: "BUBBLE", question: "Le repas pris avant l'aube s'appelle", options: ["Suhoor", "Iftar", "Diner", "Dejeuner"], correctAnswer: ["Suhoor"], explanation: "Il y a une bénédiction (Baraka) dans le Suhoor. Il donne la force physique pour jeûner la journée.", dalil: "Hadith: « Prenez le Suhoor car il y a une bénédiction dedans. »" },
  { id: "fr-q10-2", type: "MCQ", question: "Qu'est-ce que 'Laylatul Qadr' ?", options: ["La nuit du Destin", "La nuit du doute", "La fête de l'Aïd", "Une nuit normale"], correctAnswer: "La nuit du Destin", explanation: "Elle vaut mieux que 1000 mois (83 ans) d'adoration. C'est la nuit où le Coran est descendu au ciel terrestre.", dalil: "Sourate Al-Qadr" },
  { id: "fr-q10-3", type: "TRUE_FALSE", question: "Le jeûne du voyageur est obligatoire.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Le voyageur et le malade ont la permission de manger et de rattraper les jours plus tard, par miséricorde d'Allah.", dalil: "Sourate Al-Baqara 2:185" },
  { id: "fr-q10-4", type: "MATCHING", question: "Annulatifs du jeûne", options: [], pairs: [{ left: "Manger/Boire", right: "Volontairement" }, { left: "Vomissement", right: "Provoqué intentionnellement" }, { left: "Relations", right: "Pendant la journée" }], correctAnswer: "MATCH_ALL", explanation: "Si ces actes sont faits par oubli ou contrainte, le jeûne reste valide.", dalil: "-" },
  { id: "fr-q10-5", type: "BUBBLE", question: "Jeûner 6 jours de Shawwal après Ramadan équivaut à jeûner", options: ["toute", "l'", "année", "un", "mois"], correctAnswer: ["toute", "l'", "année"], explanation: "Ramadan (30 jours) + 6 jours = 36 jours. La bonne action comptant x10, cela fait 360 jours, soit une année complète !", dalil: "Hadith (Muslim)" },
  { id: "fr-q10-6", type: "MCQ", question: "Que doit dire le jeûneur si quelqu'un l'insulte ?", options: ["Répondre par une insulte", "Je suis en état de jeûne", "Se battre", "Pleurer"], correctAnswer: "Je suis en état de jeûne", explanation: "Le jeûne n'est pas seulement s'abstenir de manger, c'est aussi s'abstenir de mauvais comportements. On répond à la provocation par la paix.", dalil: "Hadith (Bukhari)" },
  { id: "fr-q10-7", type: "TRUE_FALSE", question: "Manger par oubli annule le jeûne.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Celui qui mange ou boit par oubli doit continuer son jeûne. C'est Allah qui l'a nourri et abreuvé.", dalil: "Hadith (Bukhari/Muslim)" },
  { id: "fr-q10-8", type: "MATCHING", question: "Les Portes et le Jeûne", options: [], pairs: [{ left: "Ar-Rayyan", right: "Porte du Paradis pour les jeûneurs" }, { left: "Portes du Paradis", right: "Ouvertes pendant Ramadan" }, { left: "Portes de l'Enfer", right: "Fermées pendant Ramadan" }], correctAnswer: "MATCH_ALL", explanation: "Ramadan est un mois de miséricorde exceptionnelle où les démons rebelles sont enchaînés.", dalil: "Hadith" },
  { id: "fr-q10-9", type: "MCQ", question: "Quel est le mérite du jeûne du jour de 'Arafat (pour les non-pèlerins) ?", options: ["Il efface les péchés de 2 ans", "Il rend riche", "Il guérit les maladies", "Il n'a pas de mérite spécial"], correctAnswer: "Il efface les péchés de 2 ans", explanation: "Il expie les péchés de l'année précédente et de l'année à venir (les petits péchés).", dalil: "Hadith (Muslim)" },
  { id: "fr-q10-10", type: "BUBBLE", question: "Le jeûne est un", options: ["bouclier", "contre", "le", "Feu", "épée"], correctAnswer: ["bouclier", "contre", "le", "Feu"], explanation: "Le jeûne protège des péchés dans ce monde et du châtiment de l'Enfer dans l'Au-delà.", dalil: "Hadith" }
];
const UNIT_11_FR: Question[] = [
  { id: "fr-q11-1", type: "MCQ", question: "Quel est le pilier le plus important du Hajj ?", options: ["Tawaf", "Arafat", "Mina", "Sa'i"], correctAnswer: "Arafat", explanation: "Le Prophète (sws) a dit : 'Le Hajj, c'est Arafat'. Celui qui rate le stationnement à Arafat le 9ème jour de Dhul-Hijjah a raté son Hajj.", dalil: "Hadith" },
  { id: "fr-q11-2", type: "BUBBLE", question: "On tourne autour de la Kaaba", options: ["sept", "fois", "dans", "le", "sens", "inverse"], correctAnswer: ["sept", "fois"], explanation: "Ce rite s'appelle le Tawaf. C'est comme les anges qui tournent autour du Trône d'Allah. On commence à la Pierre Noire.", dalil: "-" },
  { id: "fr-q11-3", type: "MATCHING", question: "Rites du Hajj", options: [], pairs: [{ left: "Ihram", right: "Etat de sacralisation" }, { left: "Sa'i", right: "Marche Safa-Marwa" }, { left: "Jamarat", right: "Lapidation symbolique" }], correctAnswer: "MATCH_ALL", explanation: "Chaque rite commémore l'histoire d'Ibrahim et de sa famille (Hajar, Ismail).", dalil: "-" },
  { id: "fr-q11-4", type: "TRUE_FALSE", question: "Le Hajj est obligatoire chaque année pour tout musulman.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Le Hajj n'est obligatoire qu'une seule fois dans la vie, pour celui qui en a la capacité physique et financière.", dalil: "Sourate Al Imran 3:97" },
  { id: "fr-q11-5", type: "BUBBLE", question: "La formule répétée par les pèlerins est", options: ["Labbayk", "Allahumma", "Labbayk", "Allahu", "Akbar"], correctAnswer: ["Labbayk", "Allahumma", "Labbayk"], explanation: "La Talbiyah signifie : 'Me voici, ô Allah, me voici !'. C'est la réponse à l'appel d'Ibrahim (Abraham) fait il y a des millénaires.", dalil: "-" },
  { id: "fr-q11-6", type: "MCQ", question: "Que font les pèlerins à Mina (Jamarat) ?", options: ["Ils dorment", "Ils jettent des cailloux sur des stèles", "Ils sacrifient un chameau", "Ils lisent le Coran"], correctAnswer: "Ils jettent des cailloux sur des stèles", explanation: "Cela symbolise le rejet de Satan, rappelant comment Ibrahim a chassé le diable qui tentait de l'empêcher d'obéir à Allah.", dalil: "-" },
  { id: "fr-q11-7", type: "TRUE_FALSE", question: "Le Hajj mabrour (accepté) efface tous les péchés précédents.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Celui qui fait le Hajj sans commettre de péché ni de dispute revient pur comme le jour où sa mère l'a mis au monde.", dalil: "Hadith (Bukhari)" },
  { id: "fr-q11-8", type: "MATCHING", question: "Lieux du Hajj", options: [], pairs: [{ left: "Arafat", right: "Le grand rassemblement" }, { left: "Muzdalifah", right: "Nuit à la belle étoile" }, { left: "Mina", right: "Les tentes et les Jamarat" }], correctAnswer: "MATCH_ALL", explanation: "Le pèlerin voyage entre ces différents lieux sacrés autour de La Mecque lors des jours du Hajj.", dalil: "-" },
  { id: "fr-q11-9", type: "MCQ", question: "Quel Tawaf est un pilier obligatoire du Hajj ?", options: ["Tawaf d'arrivée", "Tawaf Al-Ifada", "Tawaf d'adieu", "Tawaf volontaire"], correctAnswer: "Tawaf Al-Ifada", explanation: "Le Tawaf Al-Ifada (ou Tawaf de visite) se fait après être descendu d'Arafat et Muzdalifah. Sans lui, le Hajj n'est pas complet.", dalil: "-" },
  { id: "fr-q11-10", type: "BUBBLE", question: "Le Sa'i se fait entre les monts", options: ["Safa", "et", "Marwa", "Uhud", "Hira"], correctAnswer: ["Safa", "et", "Marwa"], explanation: "On parcourt 7 fois la distance entre ces deux collines, en souvenir de Hajar cherchant de l'eau pour son bébé Ismail.", dalil: "Sourate Al-Baqara 2:158" }
];
const UNIT_12_FR: Question[] = [
  { id: "fr-q12-1", type: "MCQ", question: "Que fait-on si on a ajouté une Rak'a par oubli ?", options: ["On refait toute la prière", "Sujud as-Sahw (Prosternation de l'oubli)", "Rien", "On demande pardon"], correctAnswer: "Sujud as-Sahw (Prosternation de l'oubli)", explanation: "L'Islam gère l'erreur humaine. On fait deux prosternations à la fin pour compenser l'oubli ou l'ajout involontaire.", dalil: "Hadith" },
  { id: "fr-q12-2", type: "BUBBLE", question: "Le Tashahhud se récite", options: ["assis", "à", "la", "fin", "de", "deux", "rakat"], correctAnswer: ["assis"], explanation: "C'est l'attestation de foi récitée assise. 'At-Tahiyyatulillah...' C'est le dialogue entre le Prophète (sws) et Allah lors de l'Ascension.", dalil: "-" },
  { id: "fr-q12-3", type: "TRUE_FALSE", question: "Bouger beaucoup sans nécessité annule la prière.", options: ["Vrai", "Faux"], correctAnswer: "Vrai", explanation: "Des mouvements excessifs, continus et inutiles qui font croire à un observateur que vous ne priez pas, annulent la prière.", dalil: "Consensus" },
  { id: "fr-q12-4", type: "MATCHING", question: "Invocations de prière", options: [], pairs: [{ left: "Sami' Allahu liman hamidah", right: "En se relevant du Ruku" }, { left: "Rabbi ighfir li", right: "Entre les deux prosternations" }, { left: "Allahu Akbar", right: "Pour changer de position" }], correctAnswer: "MATCH_ALL", explanation: "Chaque mouvement de la prière est accompagné d'une invocation spécifique pour garder le cœur connecté.", dalil: "-" },
  { id: "fr-q12-5", type: "BUBBLE", question: "La prière de consultation s'appelle", options: ["Salat", "Al-Istikhara", "Witr", "Duha"], correctAnswer: ["Salat", "Al-Istikhara"], explanation: "Quand on hésite entre deux choix licites, on prie 2 unités puis on fait l'invocation de l'Istikhara pour demander à Allah de faciliter le meilleur choix.", dalil: "Hadith (Bukhari)" },
  { id: "fr-q12-6", type: "MCQ", question: "Que faire si on arrive en retard à la prière en groupe ?", options: ["On attend la prière suivante", "On rejoint l'Imam et on complète à la fin", "On prie seul dans son coin", "On tape sur l'épaule de l'Imam"], correctAnswer: "On rejoint l'Imam et on complète à la fin", explanation: "On intègre la prière dans la position où se trouve l'Imam. Quand il termine par le Salam, on se lève pour rattraper les Rak'ats manquées.", dalil: "Hadith" },
  { id: "fr-q12-7", type: "TRUE_FALSE", question: "La prière de nuit (Tahajjud/Qiyam) est obligatoire pour tout musulman.", options: ["Vrai", "Faux"], correctAnswer: "Faux", explanation: "Elle est une Sunnah très recommandée (surérogatoire). C'était une obligation pour le Prophète (sws), mais une recommandation pour sa communauté.", dalil: "Sourate Al-Muzzammil" },
  { id: "fr-q12-8", type: "MATCHING", question: "Positions de la prière", options: [], pairs: [{ left: "Qiyam", right: "Debout" }, { left: "Ruku", right: "Incliné" }, { left: "Sujud", right: "Prosterné" }], correctAnswer: "MATCH_ALL", explanation: "La prière engage tout le corps dans la soumission : la station debout, l'inclinaison et enfin la prosternation totale.", dalil: "-" },
  { id: "fr-q12-9", type: "MCQ", question: "Qu'est-ce que la 'Sutra' ?", options: ["Une sourate du Coran", "Un objet placé devant soi quand on prie", "Un vêtement de prière", "Le tapis de prière"], correctAnswer: "Un objet placé devant soi quand on prie", explanation: "C'est une Sunnah de placer un objet (mur, chaise, sac) devant soi pour délimiter son espace de prière et empêcher les gens de passer juste devant.", dalil: "Hadith" },
  { id: "fr-q12-10", type: "BUBBLE", question: "On termine la prière en disant", options: ["Assalamu", "alaykum", "wa", "rahmatullah", "Amin"], correctAnswer: ["Assalamu", "alaykum", "wa", "rahmatullah"], explanation: "Le Taslim (salutation) se fait en tournant la tête à droite puis à gauche. C'est la sortie rituelle de la prière.", dalil: "-" }
];

